content:
@tailwind base;
@tailwind components;
@tailwind utilities;

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: 'Inter', system-ui, -apple-system, sans-serif;
  -webkit-font-smoothing: antialiased;
}

/* ── Drawdown heatmap pulse ─────────────────────────────────────────────── */
@keyframes drawdown-pulse {
  0%, 100% {
    box-shadow:
      inset 0 0 60px rgba(255, 77, 77, 0.15),
      inset 0 0 120px rgba(255, 77, 77, 0.07),
      0 0 30px rgba(255, 77, 77, 0.08);
  }
  50% {
    box-shadow:
      inset 0 0 80px rgba(255, 77, 77, 0.28),
      inset 0 0 160px rgba(255, 77, 77, 0.13),
      0 0 50px rgba(255, 77, 77, 0.15);
  }
}
